var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"미지는 두렵지 않다.","JPN":"未知は怖くない。","ENG":"I do not fear the unknown.","TWN":"未知並不可怕。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"정착을 두려워하는 이방인이 그렇듯, 그저 무지에 안주하는 삶이 두려울 뿐.","JPN":"定着を恐れる異邦人がそうであるように、ただ無知に甘んじる人生が怖いだけ。","ENG":"I am as afraid of living in ignorance as a stranger is of settling down.","TWN":"就像害怕定居的外邦人一樣，我只是害怕安於無知的生活。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어린 시절부터, 줄곧 그러하였으니.","JPN":"幼い頃から、ずっとそうだった。","ENG":"It has always been like that, ever since childhood.","TWN":"從小到大，我一向如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"으으, 무거워라…….","JPN":"うう、おもたい……","ENG":"Oof, it's so heavy...!","TWN":"呃，好重呀……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"좋아. 이렇게 커다란 의자를 딛고 올라가면 책장 꼭대기도 문제없겠지?","JPN":"よし。これだけ大きい椅子の上にあがれば、本棚のてっぺんだって手が届きますわよね？","ENG":"Okay, I should be able to reach the top of the bookcase with a chair this tall, right?","TWN":"好啦。踩到這麼大的椅子上，應該能夠到書架頂上吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"영~차!","JPN":"よ～いしょっ！","ENG":"Hup!","TWN":"嘿～咻！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"역시 난 똑똑해. 에밀리가 과자 꺼내 먹던 방법을 이럴 때 쓰다니.","JPN":"私ったらなんて賢いんでしょう。エミリーがお菓子をつまみ食いするときの方法をこういう時に利用するなんて。","ENG":"I'm so smart! No one would've thought to use Emliy's cookie stealing tricks like this!","TWN":"我果然很聰明。竟然把艾米麗偷吃餅乾的方法用在這種時候。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"어른이 되면 염소 가죽 벗기는 일도 어머님보다 더 잘하지 않을까? 흐흠.","JPN":"大人になったら、ヤギの皮を剥ぐのもお母様よりうまくやれるんじゃないかしら？　ふふん。","ENG":"Maybe I'll even be better at skinning goats than Mother when I'm older. Hehe.","TWN":"等我再長大點，剝羊皮的工作應該會做得比媽媽還好吧？呵呵。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"아차. 이럴 때가 아니지. 늦장 부리다 들키면 어머님께 혼날 거야.","JPN":"まあ。こうしている場合ではありませんわ。もたもたしてバレでもしたらお母様に怒られてしまいます。","ENG":"Oh, right! I should hurry if I don't want Mother scolding me again...","TWN":"哎呀，現在不是胡思亂想的時候。再磨蹭下去會被媽媽發現狠狠教訓的。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"어디 보자. 이 책은…….","JPN":"えっと。この本は……","ENG":"Let’s see here... This book is about...","TWN":"讓我看看，這本書……"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"두통을 일으키는 저주, 사람을 벌레로 만드는 저주, 가뭄을 부르는 저주…….","JPN":"頭痛を起こす呪い、人を虫に変える呪い、干ばつを起こす呪い……","ENG":"A curse causing headache, a curse turning people into insects, a curse summoning a famine...","TWN":"引起頭痛的詛咒，把人變成蟲子的詛咒，召喚乾旱的詛咒……"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"저주, 저주, 저주…….","JPN":"呪い、呪い、呪い……","ENG":"Curse, curse, curse...","TWN":"詛咒、詛咒、詛咒……"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"에이, 이게 뭐야. 표지만 예쁘지 순 나쁜 책이네.","JPN":"もう、何ですの。表紙がきれいなだけで悪いことしか書いてないじゃない。","ENG":"What's all this? All these books have pretty covers but are about curses.","TWN":"什麼嘛。封面那麼好看，原來是一本很糟糕的書呢。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"이 책은 어떨까? 제목이… 시시… 시식… 교전이…?","JPN":"この本はどうかしら？　タイトルが……しし……ししょく……きょうてんぎ……？","ENG":"What about this one? The title is... \\"Coolt\\"...? \\"Cultes des Goules\\"?","TWN":"這本書怎麼樣？標題是……屍屍……屍食……教典儀……？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>주술을 배우고 싶니?</color>","JPN":"<color=#ff3636>呪術を教わりたい？</color>","ENG":"<color=#ff3636>Do you want to learn sorcery?</color>","TWN":"<color=#ff3636>你想學咒術嗎？</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"응……?","JPN":"え……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"누구세요? 어디에 계신 거예요?","JPN":"どなたですの？　どこにいらっしゃるの？","ENG":"Who're you? Where are you?","TWN":"你是誰？你在哪？"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리가 가르쳐 줄게.</color>","JPN":"<color=#ff3636>我々が教えてあげる。</color>","ENG":"<color=#ff3636>We'll teach you.</color>","TWN":"<color=#ff3636>我們可以教你。</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>이계의 벌레를 부리는 비술도. 어떤 소원이든 이루어 주는 원숭이 손을 만드는 방법도.</color>","JPN":"<color=#ff3636>異界の虫を使役する秘術も。どんな願いも叶えるサルの手を作る方法も。</color>","ENG":"<color=#ff3636>Spells to command otherworldly insects, or even how to create your own Monkey's Paw that will grant you any wish.</color>","TWN":"<color=#ff3636>操控異界蟲子的秘術，還有製作可以實現任何願望的猿猴之手的方法。</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>영생의 비밀을 가르쳐 줄까? 사랑하는 사람을 손에 넣는 묘약의 제조법은?</color>","JPN":"<color=#ff3636>永生の秘密を教えてあげようか？　愛する人を手に入れる妙薬の作り方は？</color>","ENG":"<color=#ff3636>How about the secrets to immortality? Or the recipe for a love potion?</color>","TWN":"<color=#ff3636>或者你想知道永生的秘密嗎？愛情靈藥的製作方法呢？</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리는 뭐든 알고 있어. 너는 합당한 대가만 바치면 돼.</color>","JPN":"<color=#ff3636>我々は何でも知ってる。あなたはそれに見合う対価を捧げるだけでいい。</color>","ENG":"<color=#ff3636>We know all. And we will teach you for the right price.</color>","TWN":"<color=#ff3636>我們無所不知。你只要付出適當的代價就好。</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"아. 찾았다. 책장 뒤에 숨어 계셨네요.","JPN":"あ。見つけた。本棚の後に隠れていたのですね。","ENG":"Oh! I found you! You were hiding behind the bookcase.","TWN":"啊，找到了。原來你藏在書架後面啊。"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"눈이 무척 크고 예쁘세요. 꼭 보석 같아요.","JPN":"目がとても大きくてきれいですね。まるで宝石のようです。","ENG":"You have lovely eyes. They're like jewels.","TWN":"你的眼睛好大好漂亮啊，就像寶石一樣。"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리가 가진 지식이 궁금하지 않니?</color>","JPN":"<color=#ff3636>我々の知識が気にならない？</color>","ENG":"<color=#ff3636>Are you not curious about the knowledge we bear?</color>","TWN":"<color=#ff3636>你對我們擁有的知識不好奇嗎？</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>너 혼자서는 평생을 다 바쳐도 알아내지 못할 것들이야.</color>","JPN":"<color=#ff3636>あなた一人では一生かかっても見つけ出せないことばかりよ。</color>","ENG":"<color=#ff3636>It is more than what you can achieve on your own in this lifetime.</color>","TWN":"<color=#ff3636>這是用盡你一輩子也學不完的知識。</color>"},"stage":{"bg":"ESPR2_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"아뇨. 괜찮아요.","JPN":"いいえ。お構いなく。","ENG":"No, thank you.","TWN":"不，沒關係。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"정답을 먼저 알아 버리면 하나도 재미없잖아요. 그냥 제 힘으로 알아낼래요.","JPN":"正解を先に知ってしまったら面白くありませんわ。私は私の力で見つけます。","ENG":"Already knowing the answer feels like cheating. I want to figure it out by myself.","TWN":"先知道答案的話不是很無聊嗎？我想要靠我自己的力量找出答案。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"그보다 언니는 누구세요? 혹시 어머님 친구 분?","JPN":"それより、あなたはどなたですの？　もしかしてお母様の友人の方？","ENG":"But, um... Who are you? Are you a friend of Mother?","TWN":"而且這位姊姊，你是誰啊？是媽媽的朋友嗎？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"실례가 안 된다면 이름을 여쭤 봐도 될까요?","JPN":"よろしければ、お名前をお聞ききしてもよろしいかしら？","ENG":"If you won't mind, could you tell me your name?","TWN":"雖然有些失禮，不過我能問問你的名字嗎？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그건…….</color>","JPN":"<color=#ff3636>それは……</color>","ENG":"<color=#ff3636>That...</color>","TWN":"<color=#ff3636>那個……</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>지금은 모르겠어. 이름으로 불린 지 너무 오래되었으니까.</color>","JPN":"<color=#ff3636>今はわからない。長い間名前で呼ばれていなかったから。</color>","ENG":"<color=#ff3636>We do not know. It has been eons since someone called us by our name.</color>","TWN":"<color=#ff3636>不知道。已經太久沒人叫過我們的名字。</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"어휴. 자기가 누군지도 모르는데 뭘 가르쳐 준다는 거예요.","JPN":"まあ。自分が誰かも知らないのに、何を教えてくれるというのですか？","ENG":"*Sigh* How can you know all when you don't even remember your own name?","TWN":"哎呀，你連自己是誰都不知道，還說要教我什麼呀。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"어쩔 수 없네요. 언니 이름이 뭔지 똑똑한 제가 같이 고민해 드릴게요.","JPN":"仕方ありませんわね。名前が何だったか、私が一緒に考えてさしあげますわ。","ENG":"But don't worry. I'm smart, so I'll help you remember what your name was.","TWN":"那沒辦法啦。我這麼聰明，就幫姊姊想一個名字吧。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"그래야 언니네 가족들이 언니를 찾으러 왔을 때 알려 줄 수 있으니까요.","JPN":"名前がわかればお姉さんの家族が探しに来た時に教えてあげることができますもの。","ENG":"That way, I'll know if your family comes looking for you.","TWN":"那樣姊姊的家人來找姊姊的時候，我才能告訴他們。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"어때요? 저 똑똑하죠? 대견하죠?","JPN":"どうですか？　私、賢いでしょう？　褒めてくださっても構いませんよ？","ENG":"See? I'm so smart, aren't I?","TWN":"怎麼樣？我很聰明吧？很厲害吧？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서 궁금해하지 않니?</color>","JPN":"<color=#ff3636>どうして気にならないの？</color>","ENG":"<color=#ff3636>Why are you not curious?</color>","TWN":"<color=#ff3636>你為什麼不好奇呢？</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>너의 할머니의 할아버지도. 그 할아버지의 할머니까지도.</color>","JPN":"<color=#ff3636>あなたのお婆さんのお爺さんも。そのお爺さんのお婆さんまでも。</color>","ENG":"<color=#ff3636>Your grandmother's grandfather. And even his grandmother...</color>","TWN":"<color=#ff3636>你奶奶的爺爺，還有爺爺的奶奶，</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>모두들 우리가 들려 주는 이야기에 귀를 기울였는데.</color>","JPN":"<color=#ff3636>みんな我々の話を聞きたがったのに。</color>","ENG":"<color=#ff3636>They were all eager to hear what we had to say.</color>","TWN":"<color=#ff3636>他們都會被我們說的話吸引。</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"우웅…….","JPN":"うーん……","ENG":"Hmm...","TWN":"呃嗯……"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"이건 원래 비밀인데요, 브로콜리가 맛있어지는 주술을 찾는 중이었어요.","JPN":"これは秘密なのですが、ブロッコリーが美味しくなる魔法を探していたのです。","ENG":"This is supposed to be a secret, but I'm here looking for a spell that makes broccoli taste better.","TWN":"這個本來是要保密的，其實我正在找讓花椰菜變好吃的咒術。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"아버님은 브로콜리가 식사로 나올 때마다 아주 맛있다고 하면서 드시거든요.","JPN":"お父様はブロッコリーが食事に出されるたびに、とても美味しいと言ってお食べになるのですが。","ENG":"Whenever we're served something with broccoli, Father always says how delicious they are.","TWN":"因為每次吃花椰菜做的菜時，爸爸都會說很好吃。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"주술의 도움 없이 그 악랄한 야채가 맛있을 리 없잖아요.","JPN":"あのひどくまずい野菜を美味しいだなんて、魔法の力を借りているに決まっていますわ。","ENG":"But without a magical spell, there's no way that vile vegetable can taste good.","TWN":"但如果沒有咒術的幫助，那種惡毒的蔬菜，就根本不可能好吃嘛。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>무엇이든 맛있게 먹을 수 있는 방법을 알고 싶구나?</color>","JPN":"<color=#ff3636>何でも美味しく食べられる方法が知りたいのね？</color>","ENG":"<color=#ff3636>You want to know how to make everything taste good, do you not?</color>","TWN":"<color=#ff3636>原來你想知道不管什麼都能吃得香的方法啊？</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"네. 그랬어요. 방금까지는요.","JPN":"ええ。そうでした。ついさっきまでは。","ENG":"Yes. I did. Until just now.","TWN":"嗯，在不久之前是的。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"하지만 지금은 언니에 대해서 더 알고 싶어졌어요.","JPN":"でも今はお姉さんについてもっと知りたくなりました。","ENG":"You see, I'm more interested in learning about you now.","TWN":"不過，我現在比較想知道關於姊姊的事。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"언니처럼 예쁜 눈은 처음 봤거든요. 모두에게 소개해 주면 친구 사귀기도 잘한다고 놀랄 거예요.","JPN":"お姉さんのようにきれいな目は初めてですわ。紹介すれば私の交友の広さに皆さんが驚かれるはずです。","ENG":"I've never seen more beautiful eyes than yours before. If you show it to everyone else, I'm sure they'll all want to become your friend.","TWN":"我還是第一次看到像姊姊這種漂亮的眼睛。如果把你介紹給大家，他們一定會因為我交到新朋友而驚訝。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_GIRL","text":{"KOREA":"혹시 제가 언니를 곤란하게 만든 건 아니죠?","JPN":"もしかしてご迷惑でしょうか？","ENG":"But I'm not putting you in a bad spot by doing so, am I?","TWN":"會害你很困擾嗎？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>아니. 무척 기뻐.</color>","JPN":"<color=#ff3636>いいえ。とても嬉しい。</color>","ENG":"<color=#ff3636>No. We are thrilled.</color>","TWN":"<color=#ff3636>沒有，我們很開心。</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리를 궁금해한 인간은, 네가 처음이란다.</color>","JPN":"<color=#ff3636>我々自身について興味を持った人間は、あなたが初めてだから。</color>","ENG":"<color=#ff3636>You are the first human to ever take interest in us.</color>","TWN":"<color=#ff3636>想了解我們的人類，你是第一個。</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>레지나 맥크레디.</color>","JPN":"<color=#ff3636>レジーナ・マクレディー。</color>","ENG":"<color=#ff3636>Regina MacCready.</color>","TWN":"<color=#ff3636>蕾佳娜·麥克蕾蒂。</color>"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};